class Solution:
    def busiestServers(self, k, arrival, load):
        n = len(arrival)
        free_at = [0] * k
        count = [0] * k
        for i in range(n):
            start = arrival[i]
            end = start + load[i]
            assigned = -1
            for offset in range(k):
                s = (i + offset) % k
                if free_at[s] <= start:
                    assigned = s
                    break
            if assigned != -1:
                free_at[assigned] = end
                count[assigned] += 1
        mx = max(count)
        return [i for i in range(k) if count[i] == mx]

