import heapq
class Solution:
    def busiestServers(self, k, arrival, load):
        free = list(range(k))
        busy = []
        count = [0] * k
        for i in range(len(arrival)):
            start = arrival[i]
            end = start + load[i]
            while busy and busy[0][0] <= start:
                _, sid = heapq.heappop(busy)
                idx = 0
                lo, hi = 0, len(free)
                while lo < hi:
                    mid = (lo + hi) // 2
                    if free[mid] < sid:
                        lo = mid + 1
                    else:
                        hi = mid
                free.insert(lo, sid)
            if not free:
                continue
            lo, hi = 0, len(free)
            target = i % k
            while lo < hi:
                mid = (lo + hi) // 2
                if free[mid] < target:
                    lo = mid + 1
                else:
                    hi = mid
            if lo == len(free):
                lo = 0
            sid = free.pop(lo)
            count[sid] += 1
            heapq.heappush(busy, (end, sid))
        mx = max(count)
        return [i for i in range(k) if count[i] == mx]

