var busiestServers = function(k, arrival, load) {
    const freeAt = new Array(k).fill(0);
    const count = new Array(k).fill(0);
    const n = arrival.length;
    for (let i = 0; i < n; i++) {
        const start = arrival[i];
        const end = start + load[i];
        let assigned = -1;
        for (let offset = 0; offset < k; offset++) {
            const s = (i + offset) % k;
            if (freeAt[s] <= start) {
                assigned = s;
                break;
            }
        }
        if (assigned !== -1) {
            freeAt[assigned] = end;
            count[assigned] += 1;
        }
    }
    const mx = Math.max(...count);
    const res = [];
    for (let i = 0; i < k; i++) if (count[i] === mx) res.push(i);
    return res;
};
